const input = $input.first().json;

const requiredText = (fieldName) => {
  const value = String(input[fieldName] ?? '').trim();
  if (!value) {
    throw new Error(`${fieldName} is required`);
  }
  return value;
};

const optionalText = (fieldName) => {
  const value = String(input[fieldName] ?? '').trim();
  return value || undefined;
};

const optionalInt = (fieldName) => {
  const value = optionalText(fieldName);
  if (value === undefined) {
    return undefined;
  }
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed)) {
    throw new Error(`${fieldName} must be an integer when provided`);
  }
  return parsed;
};

const optionalFloat = (fieldName) => {
  const value = optionalText(fieldName);
  if (value === undefined) {
    return undefined;
  }
  const parsed = Number.parseFloat(value);
  if (!Number.isFinite(parsed)) {
    throw new Error(`${fieldName} must be numeric when provided`);
  }
  return parsed;
};

const baseUrl = requiredText('base_url').replace(/\/$/, '');
const requestBody = {};

const maxTicks = optionalInt('max_ticks');
if (maxTicks !== undefined) {
  requestBody.max_ticks = maxTicks;
}

const maxClaims = optionalInt('max_claims');
if (maxClaims !== undefined) {
  requestBody.max_claims = maxClaims;
}

const maxFlows = optionalInt('max_flows');
if (maxFlows !== undefined) {
  requestBody.max_flows = maxFlows;
}

const maxWallClockSeconds = optionalFloat('max_wall_clock_seconds');
if (maxWallClockSeconds !== undefined) {
  requestBody.max_wall_clock_seconds = maxWallClockSeconds;
}

const mode = optionalText('mode');
if (mode !== undefined) {
  requestBody.mode = mode;
}

const claimNow = optionalText('claim_now');
if (claimNow !== undefined) {
  requestBody.claim_now = claimNow;
}

return [
  {
    json: {
      base_url: baseUrl,
      request_body: requestBody,
    },
  },
];

const response = $input.first().json;
const workerLoop = response.data?.worker_loop ?? {};
const tickResults = Array.isArray(workerLoop.tick_results) ? workerLoop.tick_results : [];
const processedRunIds = [...new Set(tickResults.map((tick) => tick.claimed_run_id).filter(Boolean))];
const lastTick = tickResults.length > 0 ? tickResults[tickResults.length - 1] : null;

return [
  {
    json: {
      ok: response.ok,
      request_id: response.request_id,
      ended_reason: workerLoop.ended_reason ?? null,
      ticks_executed: workerLoop.ticks_executed ?? 0,
      claims_processed: workerLoop.claims_processed ?? 0,
      unique_flows_processed: workerLoop.unique_flows_processed ?? 0,
      runs_progressed: workerLoop.runs_progressed ?? 0,
      runs_failed_technically: workerLoop.runs_failed_technically ?? 0,
      ingestion_failures: workerLoop.ingestion_failures ?? 0,
      runs_stopped: workerLoop.runs_stopped ?? 0,
      follow_ups_created: workerLoop.follow_ups_created ?? 0,
      processed_run_ids: processedRunIds,
      last_tick_status: lastTick?.status ?? null,
      last_tick_final_run_status: lastTick?.final_run_status ?? null,
      raw_response: response,
    },
  },
];
